import { Component, h, Prop, Element } from '@stencil/core';
import { AnimationItem } from 'lottie-web';
import { twMerge } from 'tailwind-merge';

import lottie from 'lottie-web/build/player/lottie_light.min.js';
import { radialLoader } from './radial-loader';
import { RadialLabelPlacement, RadialLoaderSize } from './wdpr-radial-loader.model';

@Component({
  tag: 'wdpr-radial-loader',
  shadow: true,
})
export class WdprRadialLoader {
  private animation: AnimationItem;
  private container!: HTMLDivElement;

  /**
   * Reference to host element
   * @type {HTMLWdprRadialLoaderElement}
   */
  @Element() el: HTMLWdprRadialLoaderElement;

  /**
   * The label and aria-label
   */
  @Prop() label: string = 'Loading';
  @Prop() showLabel: boolean = false;
  @Prop() labelPlacement: RadialLabelPlacement = 'inline';
  @Prop() size: RadialLoaderSize = 'medium';

  componentDidLoad() {
    this.animation = lottie.loadAnimation({
      container: this.container,
      renderer: 'svg',
      loop: true,
      autoplay: true,
      animationData: radialLoader,
    });
  }

  disconnectedCallback() {
    if (this.animation) {
      this.animation.destroy();
    }
  }

  get layoutClass() {
    return twMerge('flex items-center gap-100', this.labelPlacement === 'inline' ? 'flex-row' : 'flex-col');
  }

  get labelClasses() {
    return twMerge(labelSizeClasses[this.size], this.showLabel ? '' : ' sr-only');
  }

  render() {
    return (
      <div class={this.layoutClass} role="status">
        <div class={loaderSizeClasses[this.size]} id="radial-loader" ref={el => (this.container = el as HTMLDivElement)} aria-hidden="true"></div>
        <span class={this.labelClasses}>{this.label}</span>
      </div>
    );
  }
}

const loaderSizeClasses: Record<RadialLoaderSize, string> = {
  large: 'size-dimension-700',
  medium: 'size-dimension-550',
  small: 'size-dimension-400',
};

const labelSizeClasses: Record<RadialLoaderSize, string> = {
  large: 'label-large',
  medium: 'label-medium',
  small: 'label-small',
};
